create or replace function public.handle_new_user()
returns trigger
language plpgsql
security definer
set search_path = public
as $func$
declare
  new_user_id uuid := new.id;
begin
  values (new_user_id, coalesce(new.raw_user_meta_data->>'nome', split_part(new.email, '@', 1)));

  select new_user_id, dia, (select id from public.disciplinas where nome = disc), ord
  from (values
    (1,'Redação',0),(1,'Biologia',1),(1,'História',2),(1,'Filosofia',3),(1,'Sociologia',4),
    (2,'Matemática',0),(2,'Química',1),(2,'Geografia',2),(2,'Biologia',3),
    (3,'Química',0),(3,'História',1),(3,'Física',2),
    (4,'Química',0),(4,'Matemática',1),(4,'Linguagens',2),
    (5,'História',0),(5,'Química',1),(5,'Biologia',2),(5,'Geografia',3)
  ) as g(dia, disc, ord);


  return new;
end;
$func$;

drop trigger if exists on_auth_user_created on auth.users;
create trigger on_auth_user_created
  after insert on auth.users
  for each row execute function public.handle_new_user();